import React, { useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { getAsset, getAssets } from '../services/api';

const pageSizeOptions = [10, 25, 50];

const valueOrDash = (value) => {
  if (value === null || value === undefined || value === '') {
    return '-';
  }
  return value;
};

const formatDate = (value) => {
  if (!value) {
    return '-';
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) {
    return value;
  }
  return date.toLocaleDateString();
};

const DetailSection = ({ title, items }) => (
  <section className="space-y-3">
    <h2 className="text-sm font-semibold text-slate-900">{title}</h2>
    <div className="rounded-xl bg-slate-100/80 px-5 py-5">
      <dl className="grid gap-x-10 gap-y-4 sm:grid-cols-2">
        {items.map((item) => (
          <div key={item.label} className="grid grid-cols-[minmax(120px,180px)_1fr] items-start gap-3 text-xs sm:text-sm">
            <dt className="text-right font-medium text-slate-700">{item.label}</dt>
            <dd className="min-w-0 break-words text-slate-950">{valueOrDash(item.value)}</dd>
          </div>
        ))}
      </dl>
    </div>
  </section>
);

const RelatedAssetsTable = ({ assets, searchTerm, onSearchTermChange }) => {
  const [pageSize, setPageSize] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);

  const filteredAssets = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) {
      return assets;
    }
    return assets.filter((asset) =>
      [asset.name, asset.product, asset.product_type, asset.asset_tag, asset.serial_number, asset.assigned_user, asset.department, asset.location]
        .filter(Boolean)
        .some((value) => value.toString().toLowerCase().includes(query))
    );
  }, [assets, searchTerm]);

  const totalPages = Math.max(1, Math.ceil(filteredAssets.length / pageSize));
  const startIndex = (currentPage - 1) * pageSize;
  const pageRows = filteredAssets.slice(startIndex, startIndex + pageSize);

  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages);
    }
  }, [currentPage, totalPages]);

  return (
    <div className="rounded-xl border border-slate-200 bg-white shadow-sm">
      <div className="flex flex-col gap-3 border-b border-slate-200 px-5 py-4 md:flex-row md:items-center md:justify-between">
        <div>
          <h2 className="text-sm font-semibold text-slate-900">Related Assets</h2>
          <p className="mt-1 text-xs text-slate-500">Assets matching the same product type.</p>
        </div>
        <div className="relative w-full md:w-72">
          <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
            <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
              <path d="M7 12A5 5 0 1 0 7 2a5 5 0 0 0 0 10ZM10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
            </svg>
          </span>
          <input
            value={searchTerm}
            onChange={(event) => {
              onSearchTermChange(event.target.value);
              setCurrentPage(1);
            }}
            placeholder="Search related assets..."
            className="w-full rounded-md border border-slate-300 bg-white py-2 pl-9 pr-3 text-sm text-slate-900 shadow-sm placeholder:text-slate-400 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500/20"
          />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full min-w-[900px] table-fixed divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              {['Asset', 'Product Type', 'Tag', 'Serial Number', 'User', 'State'].map((label) => (
                <th key={label} className="px-4 py-4 text-left text-xs font-semibold uppercase tracking-wider text-slate-500">
                  {label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200 bg-white">
            {pageRows.map((asset) => (
              <tr key={asset.id} className="transition-colors duration-150 hover:bg-slate-50">
                <td className="px-4 py-4 text-sm text-slate-900">{asset.name || asset.product || '-'}</td>
                <td className="px-4 py-4 text-sm text-slate-900">{valueOrDash(asset.product_type)}</td>
                <td className="px-4 py-4 text-sm text-slate-900">{valueOrDash(asset.asset_tag)}</td>
                <td className="px-4 py-4 text-sm text-slate-900">{valueOrDash(asset.serial_number)}</td>
                <td className="px-4 py-4 text-sm text-slate-900">{valueOrDash(asset.assigned_user)}</td>
                <td className="px-4 py-4 text-sm text-slate-900">{valueOrDash(asset.asset_state)}</td>
              </tr>
            ))}
            {pageRows.length === 0 && (
              <tr>
                <td colSpan={6} className="px-6 py-10 text-center text-sm text-slate-500">
                  No related assets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="flex flex-col gap-4 border-t border-slate-200 px-5 py-4 text-sm text-slate-600 md:flex-row md:items-center md:justify-between">
        <div className="flex items-center gap-2">
          <span>Page Size:</span>
          <select
            value={pageSize}
            onChange={(event) => {
              setPageSize(Number(event.target.value));
              setCurrentPage(1);
            }}
            className="rounded-md border border-slate-300 bg-white px-3 py-1 text-sm text-slate-900 focus:border-blue-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {pageSizeOptions.map((option) => (
              <option key={option} value={option}>{option}</option>
            ))}
          </select>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <span>{filteredAssets.length === 0 ? '0 to 0 of 0' : `${startIndex + 1} to ${Math.min(startIndex + pageSize, filteredAssets.length)} of ${filteredAssets.length}`}</span>
          <div className="flex items-center gap-2">
            <button type="button" onClick={() => setCurrentPage((page) => Math.max(1, page - 1))} disabled={currentPage === 1} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50">
              &#8592;
            </button>
            <span>Page {currentPage} of {totalPages}</span>
            <button type="button" onClick={() => setCurrentPage((page) => Math.min(totalPages, page + 1))} disabled={currentPage === totalPages} className="rounded-md border border-slate-300 px-3 py-1 text-sm text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50">
              &#8594;
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const AssetDetailsPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const [asset, setAsset] = useState(location.state?.asset || null);
  const [relatedAssets, setRelatedAssets] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(!location.state?.asset);
  const [relatedLoading, setRelatedLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    let active = true;
    const fetchAsset = async () => {
      setLoading(!asset);
      setError('');
      try {
        const response = await getAsset(id);
        if (active) {
          setAsset(response.data);
        }
      } catch (fetchError) {
        console.error('Error fetching asset:', fetchError);
        if (active) {
          setError('Unable to load asset details');
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    };
    fetchAsset();
    return () => {
      active = false;
    };
  }, [id]);

  useEffect(() => {
    if (!asset) {
      return;
    }
    let active = true;
    const fetchRelatedAssets = async () => {
      setRelatedLoading(true);
      try {
        const response = await getAssets(asset.product_type_id || undefined);
        if (active) {
          setRelatedAssets(response.data.filter((item) => item.id !== asset.id));
        }
      } catch (fetchError) {
        console.error('Error fetching related assets:', fetchError);
        if (active) {
          setRelatedAssets([]);
        }
      } finally {
        if (active) {
          setRelatedLoading(false);
        }
      }
    };
    fetchRelatedAssets();
    return () => {
      active = false;
    };
  }, [asset]);

  const sections = asset
    ? [
        {
          title: 'Asset Detail',
          items: [
            { label: 'Name', value: asset.name },
            { label: 'Product', value: asset.product },
            { label: 'Asset Tag', value: asset.asset_tag },
            { label: 'Vendor', value: asset.vendor },
            { label: 'Serial Number', value: asset.serial_number },
            { label: 'Barcode', value: asset.barcode_qr_code },
            { label: 'Description', value: asset.description },
            { label: 'Product Type', value: asset.product_type },
          ],
        },
        {
          title: 'Asset State and Location',
          items: [
            { label: 'Asset State', value: asset.asset_state },
            { label: 'User', value: asset.assigned_user },
            { label: 'Department', value: asset.department },
            { label: 'Associated To', value: asset.associated_to },
            { label: 'Site', value: asset.site },
            { label: 'Location', value: asset.location },
            { label: 'State Comments', value: asset.state_comments },
          ],
        },
        {
          title: 'Purchase Details',
          items: [
            { label: 'Acquisition Date', value: formatDate(asset.acquisition_date) },
            { label: 'Purchase Cost', value: asset.purchase_cost },
            { label: 'Expiry Date', value: formatDate(asset.expiry_date) },
            { label: 'Warranty Expiry Date', value: formatDate(asset.warranty_expiry_date) },
          ],
        },
      ]
    : [];

  return (
    <div className="space-y-5">
      <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div>
          <div className="text-sm text-slate-500">Assets &gt; Asset Details</div>
          <h1 className="mt-2 text-2xl font-semibold text-slate-900">{asset?.name || 'Asset Details'}</h1>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button type="button" onClick={() => navigate(-1)} className="inline-flex items-center gap-2 rounded-md border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-700 shadow-sm hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500">
            &#8592; Back To List
          </button>
          <button type="button" className="rounded-md bg-blue-600 px-4 py-2 text-sm font-semibold text-white shadow-sm hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500">
            Assign Asset
          </button>
        </div>
      </div>

      {loading && (
        <div className="flex items-center justify-center rounded-xl border border-slate-200 bg-white py-16 shadow-sm">
          <span className="h-10 w-10 animate-spin rounded-full border-b-2 border-t-2 border-blue-600"></span>
        </div>
      )}

      {!loading && error && (
        <div className="rounded-xl border border-red-200 bg-red-50 px-5 py-4 text-sm text-red-700">{error}</div>
      )}

      {!loading && !error && !asset && (
        <div className="rounded-xl border border-slate-200 bg-white px-6 py-12 text-center text-sm text-slate-500 shadow-sm">
          No asset details found
        </div>
      )}

      {!loading && !error && asset && (
        <>
          <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_320px]">
            <div className="rounded-xl border border-slate-200 bg-white p-5 shadow-sm">
              <div className="border-b border-slate-200">
                <div className="flex flex-wrap gap-5">
                  {['Asset Detail', 'Relationships', 'Contracts', 'Financials', 'History'].map((tab, index) => (
                    <button key={tab} type="button" className={`border-b-2 px-1 pb-3 text-sm font-medium ${index === 0 ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}>
                      {tab}
                    </button>
                  ))}
                </div>
              </div>

              <div className="mt-6 space-y-6">
                {sections.map((section) => (
                  <DetailSection key={section.title} title={section.title} items={section.items} />
                ))}
              </div>
            </div>

            <aside className="space-y-4">
              <div className="rounded-xl border border-slate-200 bg-white p-5 shadow-sm">
                <h2 className="text-sm font-semibold text-slate-900">Last Scan Status</h2>
                <dl className="mt-4 space-y-2 text-sm">
                  <div className="flex justify-between gap-4">
                    <dt className="text-slate-500">Status</dt>
                    <dd className="font-medium text-slate-900">Success</dd>
                  </div>
                  <div className="flex justify-between gap-4">
                    <dt className="text-slate-500">Last Scan Time</dt>
                    <dd className="font-medium text-slate-900">{formatDate(asset.updated_at || asset.created_at)}</dd>
                  </div>
                  <div className="flex justify-between gap-4">
                    <dt className="text-slate-500">State</dt>
                    <dd className="font-medium text-slate-900">{valueOrDash(asset.asset_state)}</dd>
                  </div>
                </dl>
              </div>

              <div className="rounded-xl border border-slate-200 bg-slate-50 p-5 shadow-sm">
                <h2 className="text-sm font-semibold text-slate-900">Assigned to User</h2>
                <div className="mt-4 flex items-center gap-3">
                  <div className="h-10 w-10 rounded-full bg-slate-400"></div>
                  <div className="text-sm font-medium text-slate-900">{valueOrDash(asset.assigned_user)}</div>
                </div>
              </div>

              <div className="rounded-xl border border-slate-200 bg-slate-50 p-5 shadow-sm">
                <h2 className="text-sm font-semibold text-slate-900">Associated Requests</h2>
                <div className="mt-4 space-y-1 text-sm text-slate-600">
                  <div>Pending: 0</div>
                  <div>Completed: 0</div>
                  <div>Total: 0</div>
                </div>
              </div>
            </aside>
          </div>

          {relatedLoading ? (
            <div className="flex items-center justify-center rounded-xl border border-slate-200 bg-white py-12 shadow-sm">
              <span className="h-10 w-10 animate-spin rounded-full border-b-2 border-t-2 border-blue-600"></span>
            </div>
          ) : (
            <RelatedAssetsTable assets={relatedAssets} searchTerm={searchTerm} onSearchTermChange={setSearchTerm} />
          )}
        </>
      )}
    </div>
  );
};

export default AssetDetailsPage;
